-- DATA-CNAE-001 (AC4): Seed cnae_setor_mapping from legacy hardcoded
-- mapping in backend/utils/cnae_mapping.py::_LEGACY_CNAE_TO_SETOR.
--
-- AUTOGENERATED BY scripts/generate_cnae_seed.py — DO NOT EDIT BY HAND.
-- To refresh, edit _LEGACY_CNAE_TO_SETOR in cnae_mapping.py then run:
--     python scripts/generate_cnae_seed.py
--
-- Idempotency: ON CONFLICT DO UPDATE preserves existing audit metadata
-- (updated_by, updated_at) when the seed value already matches.

ON CONFLICT (cnae_code) DO UPDATE
    SET setor_id   = EXCLUDED.setor_id,
        confidence = EXCLUDED.confidence,
        is_active  = EXCLUDED.is_active,
        notes      = EXCLUDED.notes,
        updated_at = now()
    WHERE
        public.cnae_setor_mapping.setor_id   IS DISTINCT FROM EXCLUDED.setor_id
     OR public.cnae_setor_mapping.confidence IS DISTINCT FROM EXCLUDED.confidence
     OR public.cnae_setor_mapping.is_active  IS DISTINCT FROM EXCLUDED.is_active
     OR public.cnae_setor_mapping.notes      IS DISTINCT FROM EXCLUDED.notes;
